    private void mostrarTopicsYEsquemas(String jsonResponse) {
        System.out.println("📋 Lista de topics v2:");
        String limpio = jsonResponse.replace("[", "").replace("]", "").replace("\"", "").trim();

        if (limpio.isEmpty()) {
            System.out.println("⚠ No se encontraron topics.");
            return;
        }

        String[] topics = limpio.split(",");
        for (String topic : topics) {
            String topicName = topic.trim();
            System.out.println("──────────────────────────────");
            System.out.println("🧩 Topic: " + topicName);

            if (descargarEsquemas) {
                Path dir = getOutputDirPath(); // Usar Path
                if (!Files.exists(dir)) {
                    try {
                        Files.createDirectories(dir);
                    } catch (Exception e) {
                        System.err.println("❌ Error creando directorio para esquemas: " + dir + " - " + e.getMessage());
                    }
                }

                comprobarYDescargarEsquema(topicName, topicName + "-key");
                comprobarYDescargarEsquema(topicName, topicName + "-value");
            } else {
                System.out.println("⏩ Descarga de esquemas desactivada, se omite " + topicName);
            }
        }
    }

    private void comprobarYDescargarEsquema(String topicName, String subject) {
        Path schemaFile = getOutputDirPath().resolve(subject + ".json"); // Usar Path

        if (Files.exists(schemaFile)) { // Usar Files.exists
            System.out.println("🗃 Esquema ya existe, se omite descarga: " + schemaFile);
        } else {
            System.out.println("⬇ Esquema no encontrado, descargando: " + subject);
            descargarYGuardarEsquema(subject, schemaFile); // Pasar Path object
        }
    }

    private void descargarYGuardarEsquema(String subject, Path fileNamePath) { // Aceptar Path
        try {
            // desactivarValidacionSSL(); // ELIMINADO: Vulnerabilidad de seguridad crítica

            String schemaUrl = schemaRegistry + "/" + subject + urlPrefix;
            System.out.println("📥 Descargando esquema desde: " + schemaUrl);

            URL url = new URL(schemaUrl);
            HttpURLConnection con = (HttpURLConnection) url.openConnection();
            con.setRequestMethod("GET");
            con.setRequestProperty("Accept", "application/vnd.schemaregistry.v1+json");

            int responseCode = con.getResponseCode();
            System.out.println("🔢 Código respuesta Registry: " + responseCode);

            if (responseCode != 200) {
                String error = "";
                if (con.getErrorStream() != null) {
                    error = new BufferedReader(new InputStreamReader(con.getErrorStream())).readLine();
                }
                System.out.println("❌ Error al obtener schema: " + error);
                return;
            }

            BufferedReader in = new BufferedReader(new InputStreamReader(con.getInputStream()));
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = in.readLine()) != null) response.append(line);
            in.close();

            com.fasterxml.jackson.databind.ObjectMapper mapper = new com.fasterxml.jackson.databind.ObjectMapper();
            com.fasterxml.jackson.databind.JsonNode root = mapper.readTree(response.toString());

            if (!root.has("schema")) {
                System.out.println("⚠ El Registry NO devolvió `schema`");
                return;
            }

            String rawSchema = root.get("schema").asText();
            com.fasterxml.jackson.databind.JsonNode schemaNode = mapper.readTree(rawSchema);

            String prettySchema = mapper.writerWithDefaultPrettyPrinter().writeValueAsString(schemaNode);

            // Usar Files.writeString para una escritura de archivos más limpia y segura
            Files.writeString(fileNamePath, prettySchema, StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);

            System.out.println("💾 Esquema guardado correctamente en: " + fileNamePath.toAbsolutePath());

        } catch (Exception e) {
            System.out.println("❌ Error descargando esquema " + subject + ": " + e.getMessage());
        }
    }

