    private List<Integer> obtenerVersionesSubjectV6(String subject) throws Exception {
        String urlStr = schemaRegistry + "/" + subject + "/versions";

        System.out.println("🌐 Llamando a: " + urlStr);

        URL url = new URL(urlStr);
        HttpURLConnection con = (HttpURLConnection) url.openConnection();
        con.setRequestMethod("GET");
        con.setRequestProperty("Accept", "application/vnd.schemaregistry.v1+json");

        int responseCode = con.getResponseCode();
        System.out.println("🔢 Código respuesta para " + subject + ": " + responseCode);

        if (responseCode != 200) {
            String error = "";
            if (con.getErrorStream() != null) {
                BufferedReader err = new BufferedReader(new InputStreamReader(con.getErrorStream()));
                error = err.readLine();
            }
            throw new RuntimeException("❌ Error obteniendo versiones del subject " + subject + ": " + error);
        }

        BufferedReader in = new BufferedReader(new InputStreamReader(con.getInputStream()));
        StringBuilder response = new StringBuilder();
        String line;
        while ((line = in.readLine()) != null) response.append(line);
        in.close();

        com.fasterxml.jackson.databind.ObjectMapper mapper = new com.fasterxml.jackson.databind.ObjectMapper();
        List<Integer> versiones = mapper.readValue(response.toString(),
                mapper.getTypeFactory().constructCollectionType(List.class, Integer.class));

        System.out.println("📌 Versiones encontradas para " + subject + ": " + versiones);

        return versiones;
    }

